// TestTrackerCommit_MalformedFreshRegularFileFailsFast verifies that a fresh
// regular file at the lock path causes fail-fast (< 100ms) without consuming
// the retry budget and that the file is left in place.
func TestTrackerCommit_MalformedFreshRegularFileFailsFast(t *testing.T) {
	root := initTrackerRepo(t)

	lockPath := trackerLockPath(root)
	require.NoError(t, os.WriteFile(lockPath, []byte("fresh"), 0o644))

	policy := LockRetryPolicy{
		InitialBackoff: 500 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     100,
		MaxElapsed:     60 * time.Second,
	}

	start := time.Now()
	err := withTrackerLockPolicy(root, policy, func() error { return nil })
	elapsed := time.Since(start)

	if err == nil {
		t.Fatalf("expected malformed-lock error, got nil")
	}
	if elapsed >= 100*time.Millisecond {
		t.Fatalf("expected fail-fast (< 100ms), took %v; err = %v", elapsed, err)
	}
	if !strings.Contains(err.Error(), "malformed") {
		t.Fatalf("expected malformed-lock diagnostic, got: %v", err)
	}

	// Fresh file must remain in place.
	info, statErr := os.Lstat(lockPath)
	if statErr != nil {
		t.Fatalf("fresh regular file was unexpectedly removed: %v", statErr)
	}
	if !info.Mode().IsRegular() {
		t.Fatalf("lock path is no longer a regular file: mode = %v", info.Mode())
	}
}

// TestTrackerCommit_MalformedSymlinkLockFailsFast verifies that a symlink at
// the lock path causes fail-fast without removing the symlink or its target.
// Skipped on platforms that do not support symlink creation.
func TestTrackerCommit_MalformedSymlinkLockFailsFast(t *testing.T) {
	root := initTrackerRepo(t)
	lockPath := trackerLockPath(root)

	targetPath := lockPath + ".target"
	require.NoError(t, os.WriteFile(targetPath, []byte("target"), 0o644))
	if err := os.Symlink(targetPath, lockPath); err != nil {
		t.Skipf("symlink creation unsupported on this platform: %v", err)
	}

	policy := LockRetryPolicy{
		InitialBackoff: 500 * time.Millisecond,
		MaxBackoff:     1 * time.Second,
		Multiplier:     2.0,
		MaxRetries:     100,
		MaxElapsed:     60 * time.Second,
	}

	start := time.Now()
	err := withTrackerLockPolicy(root, policy, func() error { return nil })
	elapsed := time.Since(start)

	if err == nil {
		t.Fatalf("expected malformed-lock error for symlink, got nil")
	}
	if elapsed >= 100*time.Millisecond {
		t.Fatalf("expected fail-fast (< 100ms), took %v; err = %v", elapsed, err)
	}
	if !strings.Contains(err.Error(), "malformed") {
		t.Fatalf("expected malformed-lock diagnostic, got: %v", err)
	}

	// Symlink must remain in place.
	if _, err := os.Lstat(lockPath); err != nil {
		t.Fatalf("symlink was removed: %v", err)
	}
	// Symlink target must remain in place.
	if _, err := os.Stat(targetPath); err != nil {
		t.Fatalf("symlink target was removed: %v", err)
	}
}

// TestTrackerCommit_MissingOwnerDoesNotReportUnknown verifies that a real lock
// directory without a pid sidecar reports "owner pid: missing" (not "unknown")
// in the timeout diagnostic.
func TestTrackerCommit_MissingOwnerDoesNotReportUnknown(t *testing.T) {
	root := initTrackerRepo(t)

	lockDir := trackerLockPath(root)
	require.NoError(t, os.MkdirAll(lockDir, 0o755))
	// Write a fresh acquired_at so age-based stale detection does not fire.
	require.NoError(t, os.WriteFile(filepath.Join(lockDir, "acquired_at"),
		[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644))
	// Deliberately omit the pid sidecar.
	defer os.RemoveAll(lockDir)

	policy := LockRetryPolicy{
		InitialBackoff: 1 * time.Millisecond,
		MaxBackoff:     1 * time.Millisecond,
		Multiplier:     1.0,
		MaxRetries:     1,
	}

	err := withTrackerLockPolicy(root, policy, func() error { return nil })
	if err == nil {
		t.Fatalf("expected lock timeout error, got nil")
	}
	if strings.Contains(err.Error(), "owner pid: unknown") {
		t.Fatalf("diagnostic must not say 'owner pid: unknown', got: %v", err)
	}
	if !strings.Contains(err.Error(), "owner pid: missing") {
		t.Fatalf("diagnostic must say 'owner pid: missing', got: %v", err)
	}
}

// TestTrackerCommit_StaleLockRecovery verifies that a stale lock left behind
// by a crashed prior process (acquired_at older than trackerLockStaleAge,
// pid pointing at a non-existent process) is forcibly broken so a later
// CommitTracker call can proceed.
func TestTrackerCommit_StaleLockRecovery(t *testing.T) {
	root := initTrackerRepo(t)
	tracker := filepath.Join(root, ddxroot.DirName, "beads.jsonl")

	// Simulate a crash: create the lock dir manually with an old timestamp
	// and a pid that does not exist.
	lockDir := trackerLockPath(root)
	require.NoError(t, os.MkdirAll(lockDir, 0o755))
	// PID 0 is reserved and signal(0) returns ESRCH on POSIX; on Windows
	// the age-based fallback handles it.
	require.NoError(t, os.WriteFile(filepath.Join(lockDir, "pid"), []byte("0"), 0o644))
	old := time.Now().Add(-2 * trackerLockStaleAge).UTC().Format(time.RFC3339)
	require.NoError(t, os.WriteFile(filepath.Join(lockDir, "acquired_at"), []byte(old), 0o644))

	// Make a tracker change so CommitTracker has something to commit.
	require.NoError(t, os.WriteFile(tracker, []byte(`{"id":"ddx-stale-test"}`+"\n"), 0o644))

	// CommitTracker must break the stale lock and succeed.
	if err := commitTrackerForTest(root); err != nil {
		t.Fatalf("CommitTracker failed to recover from stale lock: %v", err)
	}

	// Lock dir must be cleaned up.
	if _, err := os.Stat(lockDir); !os.IsNotExist(err) {
		t.Fatalf("tracker lock dir not cleaned up after stale recovery: stat err = %v", err)
	}

	// And the change must be in HEAD.
	cmd := exec.Command("git", "show", "HEAD:.ddx/beads.jsonl")
	cmd.Dir = root
	cmd.Env = scrubbedGitEnvInteg()
	out, err := cmd.CombinedOutput()
	if err != nil {
		t.Fatalf("git show HEAD:.ddx/beads.jsonl: %v\n%s", err, out)
	}
	if !strings.Contains(string(out), "ddx-stale-test") {
		t.Fatalf("tracker commit did not land: HEAD contents = %q", string(out))
	}
}

// TestTrackerCommit_RetryBackoffPolicy verifies the retry/backoff curve
// owned by this bead (ddx-da11a34a AC#4): exponential growth, capped at
// MaxBackoff, bounded by MaxRetries, and surfacing a timeout error
// (consumed upstream as lock_contention by triage, never a persisted
// status change per TD-031 §8.5).
func TestTrackerCommit_RetryBackoffPolicy(t *testing.T) {
	t.Run("step curve grows exponentially then caps", func(t *testing.T) {
		p := LockRetryPolicy{
			InitialBackoff: 10 * time.Millisecond,
			MaxBackoff:     80 * time.Millisecond,
			Multiplier:     2.0,
			MaxRetries:     10,
		}
		// n=0: 10ms, n=1: 20ms, n=2: 40ms, n=3: 80ms (cap), n=4..: 80ms.
		want := []time.Duration{
			10 * time.Millisecond,
			20 * time.Millisecond,
			40 * time.Millisecond,
			80 * time.Millisecond,
			80 * time.Millisecond,
			80 * time.Millisecond,
		}
		for i, w := range want {
			got := p.step(i)
			if got != w {
				t.Fatalf("step(%d) = %v, want %v", i, got, w)
			}
		}
	})

	t.Run("default policy has at least 3 backoff steps before exhaustion", func(t *testing.T) {
		// AC#1 (sibling triage child): "at least 3 backoff steps before
		// escalation". The lock-level policy must not exhaust before
		// triage gets a chance to escalate.
		p := DefaultLockRetryPolicy()
		if p.MaxRetries < 3 {
			t.Fatalf("DefaultLockRetryPolicy MaxRetries = %d, want >= 3", p.MaxRetries)
		}
		if p.InitialBackoff <= 0 || p.MaxBackoff <= 0 {
			t.Fatalf("DefaultLockRetryPolicy backoff bounds invalid: %+v", p)
		}
		if p.Multiplier < 1 {
			t.Fatalf("DefaultLockRetryPolicy multiplier < 1: %v", p.Multiplier)
		}
	})

	t.Run("max retries exhaustion returns timeout without crashing", func(t *testing.T) {
		root := initTrackerRepo(t)

		// Pre-acquire the lock under a fake live PID (current process)
		// so breakStaleTrackerLock cannot reclaim it.
		lockDir := trackerLockPath(root)
		require.NoError(t, os.MkdirAll(lockDir, 0o755))
		require.NoError(t, os.WriteFile(filepath.Join(lockDir, "pid"),
			[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644))
		require.NoError(t, os.WriteFile(filepath.Join(lockDir, "acquired_at"),
			[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644))
		defer os.RemoveAll(lockDir)

		policy := LockRetryPolicy{
			InitialBackoff: 1 * time.Millisecond,
			MaxBackoff:     2 * time.Millisecond,
			Multiplier:     2.0,
			MaxRetries:     3,
			MaxElapsed:     1 * time.Second,
		}

		called := false
		err := withTrackerLockPolicy(root, policy, func() error {
			called = true
			return nil
		})
		if err == nil {
			t.Fatalf("expected timeout error, got nil")
		}
		if called {
			t.Fatalf("fn must not run when lock acquisition exhausts retries")
		}
		if !strings.Contains(err.Error(), "tracker lock timeout") {
			t.Fatalf("expected tracker lock timeout error, got: %v", err)
		}
	})

	t.Run("retry succeeds when contender releases mid-curve", func(t *testing.T) {
		root := initTrackerRepo(t)
		tracker := filepath.Join(root, ddxroot.DirName, "beads.jsonl")
		require.NoError(t, os.WriteFile(tracker, []byte(`{"id":"ddx-retry-test"}`+"\n"), 0o644))

		// Hold the lock for ~50ms then release.
		lockDir := trackerLockPath(root)
		require.NoError(t, os.MkdirAll(lockDir, 0o755))
		require.NoError(t, os.WriteFile(filepath.Join(lockDir, "pid"),
			[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644))
		require.NoError(t, os.WriteFile(filepath.Join(lockDir, "acquired_at"),
			[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644))

		go func() {
			time.Sleep(50 * time.Millisecond)
			_ = os.RemoveAll(lockDir)
		}()

		// Default policy should easily ride out a 50ms hold.
		if err := commitTrackerForTest(root); err != nil {
			t.Fatalf("CommitTracker did not retry through transient contention: %v", err)
		}
	})
}

// TestTrackerLock_RecordsRetryCount asserts that TrackerLockMetricsSink
// captures a non-zero retry count under simulated lock contention.
func TestTrackerLock_RecordsRetryCount(t *testing.T) {
	root := initTrackerRepo(t)

	var mu sync.Mutex
	var captured []TrackerLockSample
	prev := TrackerLockMetricsSink
	TrackerLockMetricsSink = func(s TrackerLockSample) {
		mu.Lock()
		captured = append(captured, s)
		mu.Unlock()
	}
	defer func() { TrackerLockMetricsSink = prev }()

	// Pre-acquire the lock with the current PID so breakStaleTrackerLock
	// cannot reclaim it.
	lockDir := trackerLockPath(root)
	require.NoError(t, os.MkdirAll(lockDir, 0o755))
	require.NoError(t, os.WriteFile(filepath.Join(lockDir, "pid"),
		[]byte(fmt.Sprintf("%d", os.Getpid())), 0o644))
	require.NoError(t, os.WriteFile(filepath.Join(lockDir, "acquired_at"),
		[]byte(time.Now().UTC().Format(time.RFC3339)), 0o644))

	// Deterministic contention: release the held lock from the retry
	// loop's contended-attempt hook on the first failed Mkdir. This
	// guarantees Retries >= 1 regardless of scheduler load (a previous
	// time.Sleep(30ms) based release was flaky under parallel-package
	// load when the releaser goroutine ran before withTrackerLockPolicy
	// even reached its Mkdir call).
	var releaseOnce sync.Once
	prevHook := trackerLockContendedAttemptHook
	trackerLockContendedAttemptHook = func(int) {
		releaseOnce.Do(func() {
			_ = os.RemoveAll(lockDir)
		})
	}
	defer func() { trackerLockContendedAttemptHook = prevHook }()

	policy := LockRetryPolicy{
		InitialBackoff: 5 * time.Millisecond,
		MaxBackoff:     10 * time.Millisecond,
		Multiplier:     2.0,
		MaxRetries:     200,
		MaxElapsed:     5 * time.Second,
	}
	err := withTrackerLockPolicy(root, policy, func() error { return nil })
	require.NoError(t, err)

	mu.Lock()
	got := append([]TrackerLockSample(nil), captured...)
	mu.Unlock()

	if len(got) == 0 {
		t.Fatal("TrackerLockMetricsSink was not called")
	}
	if got[0].Retries == 0 {
		t.Fatalf("expected Retries > 0 for contended lock, got %d", got[0].Retries)
	}
	if got[0].Wait < 5*time.Millisecond {
		t.Fatalf("expected Wait >= 5ms, got %v", got[0].Wait)
	}
	if got[0].LockDir != lockDir {
		t.Fatalf("LockDir = %q, want %q", got[0].LockDir, lockDir)
	}
}

// TestTrackerLock_StaleLockAfterPartialLocalLand verifies that a worker
// that acquires withMainGitLock, successfully calls UpdateRefTo (advancing
// local main), and then crashes without releasing the lock, can be recovered
// by breakStaleTrackerLock so a subsequent worker can proceed.
func TestTrackerLock_StaleLockAfterPartialLocalLand(t *testing.T) {
	r := newLandTestRepo(t)
	ops := RealLandingGitOps{}

	// Create a second, independent commit branch to land.
	landSHA := r.commitOn(r.baseSHA, "worker.txt", "worker content\n", "feat: worker change")

	// First phase: simulate a worker that advances local main via UpdateRefTo,
	// then crash (by leaving the lock in place). We do this in a controlled way
	// inside a withMainGitLock block so we can verify UpdateRefTo succeeded.
	lockDir := trackerLockPath(r.dir)
	updateRefSucceeded := make(chan struct{})
	lockAcquired := make(chan struct{})

	go func() {
		_ = withMainGitLock(r.dir, func() error {
			close(lockAcquired)

			// Worker acquired the lock. Perform UpdateRefTo to advance main
			// locally (simulating the fast-path in Land).
			targetRef := "refs/heads/main"
			if err := ops.UpdateRefTo(r.dir, targetRef, landSHA, r.baseSHA); err != nil {
				return fmt.Errorf("UpdateRefTo failed: %w", err)
			}

			// Signal that UpdateRefTo succeeded while we hold the lock.
			close(updateRefSucceeded)

			// Now simulate a crash by panicking. This will escape the
			// withMainGitLock's defer cleanup because panic unwinds the stack
			// differently. To properly simulate this without actually panicking
			// (which would fail the test), we manually remove the defer cleanup
			// by manipulating the lock after returning from this function.
			return nil
		})

		// After exiting withMainGitLock, the defer will have cleaned up the lock.
		// We simulate the crash scenario by recreating the stale lock.
		_ = os.MkdirAll(lockDir, 0o755)
		_ = os.WriteFile(filepath.Join(lockDir, "pid"), []byte("99999"), 0o644)
		staleTime := time.Now().Add(-2 * trackerLockStaleAge).UTC().Format(time.RFC3339)
		_ = os.WriteFile(filepath.Join(lockDir, "acquired_at"), []byte(staleTime), 0o644)
	}()

	// Wait for the first worker to acquire the lock and advance main.
	select {
	case <-lockAcquired:
	case <-time.After(5 * time.Second):
		t.Fatal("worker did not acquire lock in time")
	}

	select {
	case <-updateRefSucceeded:
	case <-time.After(5 * time.Second):
		t.Fatal("UpdateRefTo did not complete in time")
	}

	// Give the first goroutine time to recreate the stale lock.
	time.Sleep(10 * time.Millisecond)

	// Verify that main has been advanced locally.
	mainTip, err := ops.ResolveRef(r.dir, "refs/heads/main")
	require.NoError(t, err)
	if mainTip != landSHA {
		t.Fatalf("main not advanced by worker: tip = %s, want = %s", mainTip, landSHA)
	}

	// Verify that the stale lock is in place.
	if _, err := os.Stat(lockDir); err != nil {
		t.Fatalf("lock dir should exist: %v", err)
	}

	// Second worker arrives and attempts to acquire the lock. It should
	// observe the stale lock, break it, and proceed with its work.
	secondWorkerErr := make(chan error, 1)
	go func() {
		secondWorkerErr <- withMainGitLock(r.dir, func() error {
			// Verify that we can see the local-ahead state (main is already at landSHA).
			tip, err := ops.ResolveRef(r.dir, "refs/heads/main")
			if err != nil {
				return fmt.Errorf("resolving main: %w", err)
			}
			if tip != landSHA {
				return fmt.Errorf("expected main at %s, got %s", landSHA, tip)
			}
			return nil
		})
	}()

	// Wait for the second worker to complete.
	select {
	case err := <-secondWorkerErr:
		require.NoError(t, err, "second worker should proceed after stale lock recovery")
	case <-time.After(5 * time.Second):
		t.Fatal("second worker did not complete in time")
	}

	// Verify the lock was cleaned up after the second worker.
	if _, err := os.Stat(lockDir); !os.IsNotExist(err) {
		t.Fatalf("lock dir should be cleaned up after second worker: stat err = %v", err)
	}
}

package agent

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/attemptmetrics"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	internalgit "github.com/DocumentDrivenDX/ddx/internal/git"
)

var durableAuditManagedPathspecs = []string{
	".ddx/beads.jsonl",
	".ddx/beads-archive.jsonl",
	".ddx/metrics/attempts.jsonl",
	".ddx/attachments",
}

type durableAuditBeadReader interface {
	Get(args ...any) (*bead.Bead, error)
}

// FinalizeDurableAttemptAudit appends the per-attempt metrics row, when the
// report carries an attempt_id, and commits any DDx-managed durable audit files
// that changed during the attempt.
func FinalizeDurableAttemptAudit(projectRoot string, store durableAuditBeadReader, report ExecuteBeadReport) error {
	if strings.TrimSpace(projectRoot) == "" {
		projectRoot = report.ProjectRoot
	}
	if strings.TrimSpace(projectRoot) == "" {
		return fmt.Errorf("finalize durable audit: project root required")
	}
	if strings.TrimSpace(report.AttemptID) != "" {
		if err := attemptmetrics.AppendRow(projectRoot, buildAttemptMetricsRow(store, report, time.Now().UTC())); err != nil {
			return fmt.Errorf("append attempt metrics: %w", err)
		}
	}
	if err := CommitDurableAuditOutputs(projectRoot, report.AttemptID); err != nil {
		return fmt.Errorf("commit durable audit outputs: %w", err)
	}
	return nil
}

// CommitDurableAuditOutputs stages and commits the DDx-managed durable audit
// paths when they are dirty. The commit is serialized through the main git lock
// so concurrent workers cannot interleave tracker and audit commits.
func CommitDurableAuditOutputs(projectRoot, attemptID string) error {
	return withTrackerLock(projectRoot, func() error {
		return commitDurableAuditOutputsLocked(projectRoot, attemptID)
	})
}

func buildAttemptMetricsRow(store durableAuditBeadReader, report ExecuteBeadReport, finishedAt time.Time) attemptmetrics.AttemptRow {
	specID := ""
	if report.BeadID != "" && store != nil {
		if b, err := store.Get(context.Background(), report.BeadID); err == nil && b != nil {
			specID, _ = b.Extra["spec-id"].(string)
		}
	}
	tsEnd := attemptmetrics.Rfc3339(finishedAt)
	tsStart := ""
	if report.DurationMS > 0 {
		start := finishedAt.Add(-time.Duration(report.DurationMS) * time.Millisecond)
		tsStart = attemptmetrics.Rfc3339(start)
	}
	return attemptmetrics.AttemptRow{
		SchemaVersion: attemptmetrics.SchemaVersion,
		AttemptID:     report.AttemptID,
		BeadID:        report.BeadID,
		SessionID:     report.SessionID,
		TSStart:       tsStart,
		TSEnd:         tsEnd,
		Model:         report.Model,
		Harness:       report.Harness,
		Profile:       report.RequestedProfile,
		Provider:      report.Provider,
		SpecID:        specID,
		Outcome:       report.Status,
		CostUSD:       report.CostUSD,
		DurationMS:    int(report.DurationMS),
		ReviewVerdict: report.ReviewVerdict,
	}
}

func commitDurableAuditOutputsLocked(projectRoot, attemptID string) error {
	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	gitDir, managedPathspecs := ddxStateGitScope(projectRoot, durableAuditManagedPathspecs...)

	out, err := internalgit.Command(ctx, gitDir, "rev-parse", "--is-inside-work-tree").Output()
	if err != nil || strings.TrimSpace(string(out)) != "true" {
		return nil
	}

	statusArgs := []string{"status", "--short", "--untracked-files=all", "--"}
	statusArgs = append(statusArgs, managedPathspecs...)
	statusOut, err := internalgit.Command(ctx, gitDir, statusArgs...).Output()
	if err != nil {
		return fmt.Errorf("checking durable audit status: %w", err)
	}
	dirtyPaths := dirtyDurableAuditPaths(string(statusOut))
	if len(dirtyPaths) == 0 {
		return nil
	}

	addArgs := []string{"add", "-A", "--"}
	addArgs = append(addArgs, dirtyPaths...)
	addOut, err := runGitWithIndexLockRecovery(ctx, gitDir, addArgs...)
	if err != nil {
		return fmt.Errorf("staging durable audit outputs: %s: %w", strings.TrimSpace(string(addOut)), err)
	}

	cachedArgs := []string{"diff", "--cached", "--"}
	cachedArgs = append(cachedArgs, dirtyPaths...)
	if cached, err := internalgit.Command(ctx, gitDir, cachedArgs...).Output(); err == nil && strings.TrimSpace(string(cached)) == "" {
		return nil
	}

	message := "commit or clean the listed implementation files before restarting ddx work"
	if len(paths) > 0 {
		message = fmt.Sprintf("commit or clean the listed implementation files before restarting ddx work: %s", strings.Join(paths, ", "))
	}
	return &OperatorAttentionStop{
		Reason:      "checkpoint_dirty",
		BeadID:      beadID,
		ProjectRoot: projectRoot,
		DirtyPaths:  paths,
		Message:     message,
	}, true
}

func parsePreExecuteCheckpointDirtyPaths(detail string) []string {
	idx := strings.Index(detail, preDispatchCheckpointDirtyRefusalPrefix)
	if idx == -1 {
		return nil
	}
	pathsField := detail[idx+len(preDispatchCheckpointDirtyRefusalPrefix):]
	if semi := strings.Index(pathsField, ";"); semi >= 0 {
		pathsField = pathsField[:semi]
	}
	var paths []string
	for _, path := range strings.Split(pathsField, ",") {
		path = strings.TrimSpace(path)
		if path != "" {
			paths = append(paths, path)
		}
	}
	return paths
}

// isTransientGitContention reports git index/ref contention errors that are
// transient under concurrent workers and must be retried rather than treated
// as a worker-stopping failure (ddx-23ac2796 and its sibling variants). It
// covers .git/index.lock conflicts plus the "unable to write new index file"
// and "cannot lock ref" forms git emits when a concurrent process holds the
// index/ref. A persistent cause (e.g. ENOSPC) simply keeps releasing+retrying
// the bead, which is still preferable to halting the whole unattended drain.
func isTransientGitContention(msg string) bool {
	if gitlock.IsIndexLockError(msg) {
		return true
	}
	lower := strings.ToLower(msg)
	for _, marker := range []string{
		"unable to write new index file",
		"cannot lock ref",
		"unable to update the ref",
	} {
		if strings.Contains(lower, marker) {
			return true
		}
	}
	return false
}

func (w *ExecuteBeadWorker) Run(ctx context.Context, rcfg config.ResolvedConfig, runtime ExecuteBeadLoopRuntime) (*ExecuteBeadLoopResult, error) {
	if w.Store == nil {
		return nil, fmt.Errorf("execute-bead loop: store is required")
	}
	if w.Executor == nil {
		return nil, fmt.Errorf("execute-bead loop: executor is required")
	}

	now := w.Now
	if now == nil {
		now = time.Now
	}
	assignee := rcfg.Assignee()
	if assignee == "" {
		assignee = "ddx"
	}
	preClaimTimeout := runtime.PreClaimTimeout
	if preClaimTimeout <= 0 {
		preClaimTimeout = work.DefaultPreClaimTimeout
	}
	noProgressCooldown := rcfg.NoProgressCooldown()
	if noProgressCooldown <= 0 {
		noProgressCooldown = 6 * time.Hour
	}
	heartbeatInterval := rcfg.HeartbeatInterval()
	if heartbeatInterval <= 0 {
		heartbeatInterval = bead.HeartbeatInterval
	}
	harness := rcfg.Harness()
	provider := rcfg.Provider()
	model := rcfg.Model()
	profile := rcfg.Profile()
	loopMode, idleInterval := runtime.loopIntent()

	result := &ExecuteBeadLoopResult{}
	resultsResetIdx := 0
	transientCandidateSkips := map[string]string{}
	w.transientCandidateSkips = transientCandidateSkips
	defer func() {
		w.transientCandidateSkips = nil
	}()
	// pausedInfraUntil is set when a no_viable_provider outcome is recorded.
	// The worker sleeps until this time (in Watch mode) before re-evaluating
	// the queue, leaving all beads immediately reclaimable. Zero means no pause.
	var pausedInfraUntil time.Time
	complexityGuard := work.NewComplexityGuard(w.ComplexityGate, runtime.Log)
	preclaimGuard := work.NewPreClaimGuard(runtime.PreClaimHook, w.Store, runtime.Log, now, 30*time.Second, preClaimTimeout)
	workLog := NewWorkLogRenderer(WorkLogRendererOptions{Now: now})
	wasIdle := false
	lastIdleQueueSignature := ""

	// Pre-claim idle escalation state (ddx-df77e668 AC #3). When the worker
	// idles on the same pre-claim blocker for preClaimIdleEscalationThreshold
	// consecutive cycles, it emits a non-terminal operator-attention event so
	// the stall is visible instead of looping silently. The streak resets when
	// the blocker detail changes or the worker stops idling on it.
	preClaimIdleDetail := ""
	preClaimIdleStreak := 0
	preClaimIdleFirstAt := time.Time{}
	preClaimIdleEscalated := false
	resetPreClaimIdleStreak := func() {
		preClaimIdleDetail = ""
		preClaimIdleStreak = 0
		preClaimIdleEscalated = false
	}

	// Worker-side liveness sidecar. Updated on each heartbeat tick so an
	// operator's `ddx work focus` / GraphQL panel can answer "is this worker
	// alive and what is it doing?" without paying tracker rewrite cost. The
	// sidecar is best-effort: write/sink failures do not interrupt the loop.
	// The reporter is constructed here but does NOT emit until a bead is
	// claimed — that order keeps loop.start as the first envelope on the
	// EventSink so structured-event consumers continue to see it.
	var liveness *work.SidecarLivenessReporter
	if runtime.ProjectRoot != "" && runtime.SessionID != "" {
		liveness = work.NewSidecarLivenessReporter(runtime.ProjectRoot, runtime.SessionID, runtime.SessionID, runtime.EventSink)
	}

	emit := func(eventType string, data map[string]any) {
		writeLoopEvent(runtime.EventSink, runtime.SessionID, eventType, data, now().UTC())
	}
	claimSuccessRateWindowSize := runtime.effectiveClaimSuccessRateWindow()
	claimSuccessRateThreshold := runtime.effectiveClaimSuccessRateThreshold()
	claimSuccessRateWindow := make([]bool, 0, claimSuccessRateWindowSize)
	claimSuccessRateSuccesses := 0
	claimSuccessRateWarned := false
	preClaimWarnThreshold := runtime.effectivePreClaimWarnRepeatThreshold()
	preClaimWarnState := preClaimWarnRepeatState{}
	// exitReason is populated as the loop exits to surface a structured reason
	// in the loop.end event (ddx-dc157075 AC #4). Work-owned terminal reasons
	// are classified through work.StopCondition; fatal_config,
	// preflight_failed, resource_exhausted, and future provider exhaustion are
	// still subsystem-specific exits.
	exitReason := ""
	setExit := func(condition, reason string) {
		exitReason = reason
		result.StopCondition = condition
		result.ExitReason = reason
	}
	appendPreClaimWarn := func(beadID, reason, detail string, at time.Time) bool {
		escalated := appendPreClaimIntakeWarning(w.Store, emit, &preClaimWarnState, preClaimWarnThreshold, beadID, assignee, reason, detail, at)
		if !escalated {
			return false
		}
		detailText := fmt.Sprintf(
			"pre-claim warn fingerprint repeated %d times across %d distinct bead IDs",
			preClaimWarnState.Count,
			len(preClaimWarnState.DistinctBeadIDs),
		)
		result.OperatorAttention = &OperatorAttentionStop{
			Reason:      "preclaim_warn_repeated",
			BeadID:      beadID,
			ProjectRoot: runtime.ProjectRoot,
			Message:     detailText,
		}
		setExit("OperatorAttention", "operator_attention")
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "operator attention: %s\n", detailText)
		}
		return true
	}
	recordClaimAttempt := func(success bool, beadID string) {
		if claimSuccessRateWindowSize <= 0 {
			return
		}
		if len(claimSuccessRateWindow) == claimSuccessRateWindowSize {
			if claimSuccessRateWindow[0] {
				claimSuccessRateSuccesses--
			}
			copy(claimSuccessRateWindow, claimSuccessRateWindow[1:])
			claimSuccessRateWindow = claimSuccessRateWindow[:claimSuccessRateWindowSize-1]
		}
		claimSuccessRateWindow = append(claimSuccessRateWindow, success)
		if success {
			claimSuccessRateSuccesses++
			claimSuccessRateWarned = false
			return
		}
		if len(claimSuccessRateWindow) < claimSuccessRateWindowSize {
			return
		}
		rate := float64(claimSuccessRateSuccesses) / float64(claimSuccessRateWindowSize)
		if rate > claimSuccessRateThreshold || claimSuccessRateWarned {
			return
		}
		claimSuccessRateWarned = true
		detail := fmt.Sprintf(
			"claim success rate %.3f over the last %d claim attempts (%d successes, %d non-successes) is at or below threshold %.3f; manual intervention may be required",
			rate,
			claimSuccessRateWindowSize,
			claimSuccessRateSuccesses,
			claimSuccessRateWindowSize-claimSuccessRateSuccesses,
			claimSuccessRateThreshold,
		)
		emit("loop.operator_attention", map[string]any{
			"reason":        "claim_success_rate_below_threshold",
			"bead_id":       beadID,
			"detail":        detail,
			"window_size":   claimSuccessRateWindowSize,
			"successes":     claimSuccessRateSuccesses,
			"non_successes": claimSuccessRateWindowSize - claimSuccessRateSuccesses,
			"success_rate":  rate,
			"threshold":     claimSuccessRateThreshold,
		})
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "operator attention: %s\n", detail)
		}
	}
	clearTransientCandidateSkips := func() {
		for beadID := range transientCandidateSkips {
			delete(transientCandidateSkips, beadID)
		}
	}
	stopAfterNonAttemptSkip := func() bool {
		return loopMode == executeloop.ModeOnce && runtime.TargetBeadID != ""
	}
	strictIntakeBlocking := func() bool {
		return runtime.TargetBeadID != ""
	}

	emit("loop.start", map[string]any{
		"worker_id":    runtime.WorkerID,
		"project_root": runtime.ProjectRoot,
		"harness":      harness,
		"model":        model,
		"session_id":   runtime.SessionID,
		"assignee":     assignee,
		"mode":         string(loopMode),
		"once":         loopMode == executeloop.ModeOnce,
	})
	cleanupLog := runtime.CleanupLog
	if cleanupLog == nil {
		cleanupLog = runtime.Log
	}
	cleanupStop := startExecutionCleanupWorker(ctx, runtime.ProjectRoot, runtime.CleanupRunner, runtime.CleanupInterval, runtime.CleanupTickCh, cleanupLog, emit)
	attemptStarted := false
	defer func() {
		cleanupStop(ctx.Err() != nil && attemptStarted)
	}()
	_, _, _ = runExecutionCleanupPass(ctx, runtime.ProjectRoot, runtime.CleanupRunner, cleanupLog, emit, "startup")
	leaseReader, _ := w.Store.(orphanHarnessLeaseReader)
	releaser, _ := w.Store.(orphanHarnessLeaseReleaser)
	appender, _ := w.Store.(orphanHarnessEventAppender)
