	}
	if cfg.Git == nil {
		return "", nil
	}
	acCfg := gitpkg.AutoCommitConfig{
		AutoCommit:    cfg.Git.AutoCommit,
		CommitPrefix:  cfg.Git.CommitPrefix,
		IncludeStaged: includeStaged,
	}
