// the Fizeau harness (session_id/seq/type/ts/data) so existing event
// consumers can parse the stream uniformly. Errors are swallowed:
// structured logging must never break the core work.
func writeLoopEvent(sink io.Writer, sessionID, eventType string, data map[string]any, ts time.Time) {
	if sink == nil {
		return
	}
	if data == nil {
		data = map[string]any{}
	}
	entry := map[string]any{
		"session_id": sessionID,
		"type":       eventType,
		"ts":         ts.UTC().Format(time.RFC3339Nano),
		"data":       data,
	}
	line, err := json.Marshal(entry)
	if err != nil {
		return
	}
	frame := make([]byte, len(line)+1)
	copy(frame, line)
	frame[len(line)] = '\n'
	_, _ = sink.Write(frame)
}

var trackerLockMetricsSinkInstallMu sync.Mutex

func installWorkerTrackerLockMetricsSink(runtime ExecuteBeadLoopRuntime, now func() time.Time) func() {
	if runtime.Log == nil && runtime.EventSink == nil {
		return func() {}
	}
	if now == nil {
		now = time.Now
	}

	var writeMu sync.Mutex
	sink := func(sample TrackerLockSample) {
		writeMu.Lock()
		defer writeMu.Unlock()

		data := map[string]any{
			"section": sample.Section,
			"wait":    sample.Wait.String(),
			"hold":    sample.Hold.String(),
			"retries": sample.Retries,
		}
		writeLoopEvent(runtime.EventSink, runtime.SessionID, "loop.tracker_lock", data, now().UTC())
		if runtime.Log != nil {
			_, _ = fmt.Fprintf(runtime.Log, "tracker_lock section=%s wait=%s hold=%s retries=%d\n",
				sample.Section, sample.Wait, sample.Hold, sample.Retries)
		}
	}

	trackerLockMetricsSinkInstallMu.Lock()
	previous := TrackerLockMetricsSink
	TrackerLockMetricsSink = sink
	trackerLockMetricsSinkInstallMu.Unlock()

	return func() {
		trackerLockMetricsSinkInstallMu.Lock()
		TrackerLockMetricsSink = previous
		trackerLockMetricsSinkInstallMu.Unlock()
	}
}

