+			"section": sample.Section,
+			"wait":    sample.Wait.String(),
+			"hold":    sample.Hold.String(),
+			"retries": sample.Retries,
+		}
+		writeLoopEvent(runtime.EventSink, runtime.SessionID, "loop.tracker_lock", data, now().UTC())
