+			_, _ = fmt.Fprintf(runtime.Log, "tracker_lock section=%s wait=%s hold=%s retries=%d\n",
+				sample.Section, sample.Wait, sample.Hold, sample.Retries)
+		}
+	}
+
+	trackerLockMetricsSinkInstallMu.Lock()
+	previous := TrackerLockMetricsSink
+	TrackerLockMetricsSink = sink
+	trackerLockMetricsSinkInstallMu.Unlock()
+
+	return func() {
+		trackerLockMetricsSinkInstallMu.Lock()
+		TrackerLockMetricsSink = previous
+		trackerLockMetricsSinkInstallMu.Unlock()
+	}
+}
