+func TestTrackerLock_WorkerInstalledSinkEmitsEventAndLog(t *testing.T) {
+	root := initTrackerRepo(t)
+
+	var eventSink bytes.Buffer
+	var log bytes.Buffer
+	restore := installWorkerTrackerLockMetricsSink(ExecuteBeadLoopRuntime{
+		EventSink: &eventSink,
+		Log:       &log,
+		SessionID: "test-session",
+	}, func() time.Time { return time.Unix(0, 0) })
+	defer restore()
+
+	err := withTrackerLock(root, "pre_dispatch", func() error { return nil })
+	require.NoError(t, err)
+
+	logLine := log.String()
+	require.Contains(t, logLine, "tracker_lock section=pre_dispatch")
+	require.Contains(t, logLine, " wait=")
+	require.Contains(t, logLine, " hold=")
+	require.Contains(t, logLine, " retries=0")
+
+	lines := strings.Split(strings.TrimSpace(eventSink.String()), "\n")
+	require.Len(t, lines, 1)
+	var event map[string]any
+	require.NoError(t, json.Unmarshal([]byte(lines[0]), &event))
+	require.Equal(t, "test-session", event["session_id"])
+	require.Equal(t, "loop.tracker_lock", event["type"])
+	data, ok := event["data"].(map[string]any)
+	require.True(t, ok, "event data missing or wrong type")
+	require.Equal(t, "pre_dispatch", data["section"])
+	require.NotEmpty(t, data["wait"])
+	require.NotEmpty(t, data["hold"])
+	require.Equal(t, float64(0), data["retries"])
+}
